SELECT c.provider_no, c.charge_dt, p.provider_name FROM charge AS c JOIN member AS m ON c.member_no = m.member_no LEFT JOIN payment AS pay ON m.member_no = pay.member_no JOIN provider AS p ON c.provider_no = p.provider_no WHERE (c.category_no = 3) AND (strftime('%Y-%m', c.charge_dt) = strftime('%Y-%m', pay.payment_dt) OR pay.payment_dt IS NULL) GROUP BY c.provider_no, c.charge_dt, p.provider_name
